using Dapper;
using Microsoft.Extensions.Logging;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
using Valora.Application.ReadModels;
using Valora.Application.Security;
namespace Valora.Infrastructure.Repositories;
public sealed class SurveyRepository(IDbConnectionFactory f, ILogger<SurveyRepository> logger):ISurveyRepository
{
    public async Task<SurveyPublicReadModel?> GetPublicByTokenAsync(string token){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyPublicReadModel>(BaseSql+" AND (s.token_hash=@token OR EXISTS (SELECT 1 FROM valorapesquisa.survey_links sl WHERE sl.survey_id=s.id AND sl.token_hash=@token AND sl.is_deleted=false AND sl.status='active' AND sl.revoked_at IS NULL AND (sl.expires_at IS NULL OR sl.expires_at>now() OR "+FreeOfficialSql+")))",new{token});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar pesquisa pública por token. Token={Token}",LogSanitizer.MaskToken(token));throw;}}
    public async Task<SurveyPublicReadModel?> GetActivePublicSurveyAsync(Guid surveyId){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyPublicReadModel>(BaseSql+" AND s.id=@surveyId",new{surveyId});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar pesquisa pública ativa. SurveyId={SurveyId}",surveyId);throw;}}
    public async Task<SurveyLinkReadModel?> GetPublicLinkAsync(Guid surveyId){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyLinkReadModel>("SELECT sl.id,sl.survey_id AS SurveyId,sl.public_url AS PublicUrl,sl.status,sl.starts_at AS StartsAt,sl.expires_at AS ExpiresAt FROM valorapesquisa.survey_links sl JOIN valorapesquisa.surveys s ON s.id=sl.survey_id JOIN valorapesquisa.organizations o ON o.id=s.organization_id JOIN valorapesquisa.forms fo ON fo.id=s.form_id WHERE sl.survey_id=@surveyId AND sl.is_deleted=false AND sl.status='active' AND sl.revoked_at IS NULL AND s.is_deleted=false AND s.status IN ('active','published','open') AND o.is_deleted=false AND o.status='active' AND fo.is_deleted=false AND (sl.starts_at IS NULL OR sl.starts_at<=now()) AND (sl.expires_at IS NULL OR sl.expires_at>now() OR "+FreeOfficialSql+") ORDER BY sl.created_at DESC LIMIT 1",new{surveyId});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar link público ativo. SurveyId={SurveyId}",surveyId);throw;}}
    public async Task<bool> ValidatePublicTokenAsync(Guid surveyId,string token){try{using var c=f.Create(); var ok=await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.survey_links sl JOIN valorapesquisa.surveys s ON s.id=sl.survey_id JOIN valorapesquisa.organizations o ON o.id=s.organization_id JOIN valorapesquisa.forms fo ON fo.id=s.form_id WHERE sl.survey_id=@surveyId AND sl.token_hash=@token AND sl.status='active' AND sl.is_deleted=false AND sl.revoked_at IS NULL AND s.is_deleted=false AND s.status IN ('active','published','open') AND o.is_deleted=false AND o.status='active' AND fo.is_deleted=false AND (sl.expires_at IS NULL OR sl.expires_at>now() OR "+FreeOfficialSql+")",new{surveyId,token}); if(ok>0)return true; return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.surveys s JOIN valorapesquisa.organizations o ON o.id=s.organization_id JOIN valorapesquisa.forms fo ON fo.id=s.form_id WHERE s.id=@surveyId AND s.token_hash=@token AND s.is_deleted=false AND s.revoked_at IS NULL AND s.status IN ('active','published','open') AND o.is_deleted=false AND o.status='active' AND fo.is_deleted=false AND (s.expires_at IS NULL OR s.expires_at>now() OR "+FreeOfficialSql+")",new{surveyId,token})>0;}catch(Exception ex){logger.LogError(ex,"Erro ao validar token público. SurveyId={SurveyId} Token={Token}",surveyId,LogSanitizer.MaskToken(token));throw;}}
    public async Task<Guid> SaveResponseAsync(Guid surveyId,SubmitResponseRequest request){try{using var c=f.Create(); var survey=await GetActivePublicSurveyAsync(surveyId); if(survey is null) throw new InvalidOperationException("Pesquisa pública indisponível para submissão."); var id=Guid.NewGuid(); await c.ExecuteAsync("INSERT INTO valorapesquisa.responses(id,organization_id,survey_id,form_id,participant_name,participant_email,status,completed_at) VALUES (@id,@organizationId,@surveyId,@formId,@participantName,@participantEmail,'completed',now())",new{id,organizationId=survey.OrganizationId,surveyId,formId=survey.FormId,participantName=request.ParticipantName,participantEmail=request.ParticipantEmail}); logger.LogInformation("Resposta pública salva por rota compatível. SurveyId={SurveyId} ResponseId={ResponseId}",surveyId,id); return id;}catch(Exception ex){logger.LogError(ex,"Erro ao salvar resposta pública compatível. SurveyId={SurveyId} Email={Email}",surveyId,LogSanitizer.MaskEmail(request.ParticipantEmail));throw;}}
    public async Task<int> CountActiveSurveysAsync(Guid organizationId){try{using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.surveys WHERE organization_id=@organizationId AND status='active' AND is_deleted=false",new{organizationId});}catch(Exception ex){logger.LogError(ex,"Erro ao contar pesquisas ativas. OrganizationId={OrganizationId}",organizationId);throw;}}
    public async Task<int> CountResponsesThisMonthAsync(Guid organizationId){try{using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.responses WHERE organization_id=@organizationId AND created_at >= date_trunc('month', now()) AND is_deleted=false",new{organizationId});}catch(Exception ex){logger.LogError(ex,"Erro ao contar respostas do mês. OrganizationId={OrganizationId}",organizationId);throw;}}
    private static bool IsFreeOfficialSurvey(bool isFree,string? planId,string? title)=>isFree||string.Equals(planId,"free",StringComparison.OrdinalIgnoreCase)||(title?.Contains("Valora Insight",StringComparison.OrdinalIgnoreCase)??false)||(title?.Contains("Diagnóstico gratuito",StringComparison.OrdinalIgnoreCase)??false);
    const string FreeOfficialSql="(s.is_free=true OR lower(coalesce(s.plan_id,''))='free' OR s.title ILIKE '%Valora Insight%' OR s.title ILIKE '%Diagnóstico gratuito%')";
    const string BaseSql="SELECT s.id,s.organization_id AS OrganizationId,s.form_id AS FormId,s.title,s.description,s.status,s.lgpd_required AS LgpdRequired,o.name AS OrganizationName,o.public_name AS PublicName,o.slug AS OrganizationSlug,s.starts_at AS StartsAt,s.expires_at AS ExpiresAt FROM valorapesquisa.surveys s JOIN valorapesquisa.organizations o ON o.id=s.organization_id JOIN valorapesquisa.forms fo ON fo.id=s.form_id WHERE s.is_deleted=false AND s.revoked_at IS NULL AND s.status IN ('active','published','open') AND o.is_deleted=false AND o.status='active' AND fo.is_deleted=false AND (s.starts_at IS NULL OR s.starts_at<=now()) AND (s.expires_at IS NULL OR s.expires_at>now() OR "+FreeOfficialSql+")";

    public async Task<IReadOnlyList<dynamic>> ListAdminAsync(Guid organizationId){try{using var c=f.Create(); return (await c.QueryAsync("SELECT s.id,s.organization_id,s.form_id,s.title,s.description,s.status,s.public_slug,s.public_url,s.starts_at,s.expires_at,s.created_at,s.updated_at,f.name AS form_name FROM valorapesquisa.surveys s LEFT JOIN valorapesquisa.forms f ON f.id=s.form_id WHERE s.organization_id=@organizationId AND s.is_deleted=false ORDER BY s.created_at DESC",new{organizationId})).ToList();}catch(Exception ex){logger.LogError(ex,"Erro ao listar pesquisas. OrganizationId={OrganizationId}",organizationId);throw;}}
    public async Task<dynamic?> GetAdminAsync(Guid organizationId,Guid surveyId){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT s.id,s.organization_id,s.form_id,s.title,s.description,s.status,s.public_slug,s.public_url,s.starts_at,s.expires_at,s.created_at,s.updated_at,f.name AS form_name FROM valorapesquisa.surveys s LEFT JOIN valorapesquisa.forms f ON f.id=s.form_id WHERE s.id=@surveyId AND s.organization_id=@organizationId AND s.is_deleted=false",new{organizationId,surveyId});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar pesquisa administrativa. OrganizationId={OrganizationId} SurveyId={SurveyId}",organizationId,surveyId);throw;}}
    public async Task<Guid> CreateAdminAsync(Guid organizationId,Guid formId,string title,string? description,string status){try{using var c=f.Create(); var tokenHash=Convert.ToHexString(System.Security.Cryptography.SHA256.HashData(System.Text.Encoding.UTF8.GetBytes(Guid.NewGuid().ToString("N")))).ToLowerInvariant(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valorapesquisa.surveys(organization_id,form_id,title,description,status,token_hash) VALUES (@organizationId,@formId,@title,@description,@status,@tokenHash) RETURNING id",new{organizationId,formId,title,description,status,tokenHash});}catch(Exception ex){logger.LogError(ex,"Erro ao criar pesquisa. OrganizationId={OrganizationId} FormId={FormId}",organizationId,formId);throw;}}
    public async Task UpdateAdminAsync(Guid organizationId,Guid surveyId,Guid? formId,string? title,string? description,string? status){try{using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.surveys SET form_id=COALESCE(@formId,form_id),title=COALESCE(@title,title),description=COALESCE(@description,description),status=COALESCE(@status,status),updated_at=now() WHERE id=@surveyId AND organization_id=@organizationId AND is_deleted=false",new{organizationId,surveyId,formId,title,description,status});}catch(Exception ex){logger.LogError(ex,"Erro ao atualizar pesquisa. OrganizationId={OrganizationId} SurveyId={SurveyId}",organizationId,surveyId);throw;}}
    public async Task UpdateStatusAdminAsync(Guid organizationId,Guid surveyId,string status){try{using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.surveys SET status=@status,updated_at=now() WHERE id=@surveyId AND organization_id=@organizationId AND is_deleted=false",new{organizationId,surveyId,status});}catch(Exception ex){logger.LogError(ex,"Erro ao atualizar status da pesquisa. OrganizationId={OrganizationId} SurveyId={SurveyId}",organizationId,surveyId);throw;}}
    public async Task<IReadOnlyList<dynamic>> ListLinksAdminAsync(Guid organizationId,Guid surveyId){try{using var c=f.Create(); return (await c.QueryAsync("SELECT id,organization_id,survey_id,public_url,status,starts_at,expires_at,created_at,updated_at FROM valorapesquisa.survey_links WHERE organization_id=@organizationId AND survey_id=@surveyId AND is_deleted=false ORDER BY created_at DESC",new{organizationId,surveyId})).ToList();}catch(Exception ex){logger.LogError(ex,"Erro ao listar links. OrganizationId={OrganizationId} SurveyId={SurveyId}",organizationId,surveyId);throw;}}
    public async Task<Guid> CreateLinkAdminAsync(Guid organizationId,Guid surveyId,string tokenHash,string publicUrl,DateTimeOffset? expiresAt){try{using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valorapesquisa.survey_links(organization_id,survey_id,token_hash,public_url,expires_at,status) VALUES (@organizationId,@surveyId,@tokenHash,@publicUrl,@expiresAt,'active') RETURNING id",new{organizationId,surveyId,tokenHash,publicUrl,expiresAt});}catch(Exception ex){logger.LogError(ex,"Erro ao criar link. OrganizationId={OrganizationId} SurveyId={SurveyId}",organizationId,surveyId);throw;}}
    public async Task UpdateLinkStatusAdminAsync(Guid organizationId,Guid linkId,string status){try{using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.survey_links SET status=@status,revoked_at=CASE WHEN @status IN ('revoked','inactive') THEN now() ELSE revoked_at END,updated_at=now() WHERE id=@linkId AND organization_id=@organizationId AND is_deleted=false",new{organizationId,linkId,status});}catch(Exception ex){logger.LogError(ex,"Erro ao atualizar link. OrganizationId={OrganizationId} LinkId={LinkId}",organizationId,linkId);throw;}}

}
